import './DropDownContent.scss';

import type { JSX } from 'react';
import React from 'react';

import type { FilterProps } from '../Filter';
import { Filter } from '../Filter';
import type { OptionsProps } from '../Options';
import { Options } from '../Options';

interface DropDownContent<T> extends OptionsProps<T>, FilterProps {
	selectRef: React.MutableRefObject<HTMLDivElement>;
	unstyled?: boolean;
}

export const DropDownContent = <T,>({
	selectedItems,
	optionsData,
	selectAll,
	filter,
	filterValue,
	filterFunction,
	selectAllIndex,
	optionsClassName,
	multiple,
	itemClassName,
	onMultiselectItem,
	onManualClickOption,
	onSelectItem,
	focusedIndex,
	handleSelectAll,
	makeOption,
	showTooltip,
	defaultMakeOption,
	selectAllText,
	loading,
	loadingText,
	loadingContent,
	noOptionsText,
	optionsRef,
	selectStatus,
	filterPlaceholder,
	filterRef,
	changeFilterValue,
	dataTestId,
	selectRef,
	makeOptionWrapper,
	groups,
	unstyled = false,
}: DropDownContent<T>): React.JSX.Element => (
	<div
		className={unstyled ? undefined : 'dsb__select__dropdown-content'}
		data-testid={dataTestId + '-dropdown-content'}
		ref={selectRef}
	>
		{filter && (
			<Filter
				filterPlaceholder={filterPlaceholder}
				filterRef={filterRef}
				changeFilterValue={changeFilterValue}
				filterValue={filterValue}
				dataTestId={dataTestId}
			/>
		)}
		{/* TODO Нормализоват пропсы для этого компонента, сейчас слишком много зависимостей */}
		<Options<T>
			selectedItems={selectedItems}
			optionsData={optionsData}
			selectAll={selectAll}
			filter={filter}
			filterValue={filterValue}
			filterFunction={filterFunction}
			selectAllIndex={selectAllIndex}
			optionsClassName={optionsClassName}
			multiple={multiple}
			itemClassName={itemClassName}
			onMultiselectItem={onMultiselectItem}
			onManualClickOption={onManualClickOption}
			onSelectItem={onSelectItem}
			focusedIndex={focusedIndex}
			handleSelectAll={handleSelectAll}
			makeOption={makeOption}
			showTooltip={showTooltip}
			defaultMakeOption={defaultMakeOption}
			selectAllText={selectAllText}
			loading={loading}
			loadingText={loadingText}
			loadingContent={loadingContent}
			noOptionsText={noOptionsText}
			optionsRef={optionsRef}
			selectStatus={selectStatus}
			makeOptionWrapper={makeOptionWrapper}
			groups={groups}
			dataTestId={dataTestId}
		/>
	</div>
);
